import { Component, computed, effect, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { MoneyPipe } from '../../core/pipes/money.pipe';
import { CartService } from '../../core/services/cart.service';
import { CartItem } from '../../core/models/storefront.models';

@Component({
  selector: 'app-cart',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './cart.component.html',
})
export class CartComponent {
  items = signal<CartItem[]>([
    {
      id: 'ci1',
      productId: 'p1',
      qty: 1,
      product: {
        id: 'p1',
        name: 'Aurora Wireless Headphones',
        description: 'Over-ear noise-cancelling headphones.',
        priceCents: 14999,
        imageUrl: 'https://picsum.photos/seed/headphones/160/160',
        stockQty: 12,
      },
    },
    {
      id: 'ci2',
      productId: 'p2',
      qty: 2,
      product: {
        id: 'p2',
        name: 'Nimbus Mechanical Keyboard',
        description: 'Hot-swappable 75% keyboard.',
        priceCents: 9900,
        imageUrl: 'https://picsum.photos/seed/keyboard/160/160',
        stockQty: 34,
      },
    },
  ]);

  subtotal = computed(() =>
    this.items().reduce((sum, i) => sum + i.product.priceCents * i.qty, 0),
  );
  itemCount = computed(() => this.items().reduce((sum, i) => sum + i.qty, 0));

  constructor(private cart: CartService) {
    // Keep the navbar badge in sync with the visible cart.
    effect(() => this.cart.count.set(this.itemCount()));
  }

  changeQty(item: CartItem, delta: number): void {
    const next = item.qty + delta;
    if (next <= 0) {
      this.remove(item);
      return;
    }
    this.items.update((list) =>
      list.map((i) => (i.id === item.id ? { ...i, qty: next } : i)),
    );
  }

  remove(item: CartItem): void {
    this.items.update((list) => list.filter((i) => i.id !== item.id));
  }
}
